<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
    <title>Kanban Board</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            margin: 20px;
            background-color: #f9f9f9;
        }
        .board {
            display: flex;
            gap: 20px;
        }
        [id^=col-] {
            flex: 1;
            min-height: 400px;
            background: white;
            border-radius: 8px;
            padding: 15px;
            box-shadow: 0 2px 6px rgba(0,0,0,0.05);
        }
        .header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 10px;
            font-weight: bold;
        }
        .count {
            color: #888;
        }
        .card-container {
            min-height: 250px;
        }
        .card {
            background-color: #eaeaea;
            padding: 10px 12px;
            margin-bottom: 10px;
            border-radius: 4px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            cursor: move;
        }
        .card-del {
            background: none;
            border: none;
            font-size: 16px;
            color: #999;
            cursor: pointer;
        }
        .controls {
            margin-bottom: 20px;
        }
        #new-card {
            flex-grow: 1;
            padding: 8px;
            font-size: 14px;
        }
        #add-card {
            padding: 8px 12px;
            font-size: 14px;
            margin-left: 5px;
        }
    </style>
</head>
<body>
    <div class="controls">
        <input id="new-card" type="text" placeholder="New card title"/>
        <button id="add-card">Add</button>
    </div>
    <div class="board">
        <section id="col-todo">
            <div class="header"><span>To Do</span><span class="count">(0)</span></div>
            <div class="card-container"></div>
        </section>
        <section id="col-doing">
            <div class="header"><span>Doing</span><span class="count">(0)</span></div>
            <div class="card-container"></div>
        </section>
        <section id="col-done">
            <div class="header"><span>Done</span><span class="count">(0)</span></div>
            <div class="card-container"></div>
        </section>
    </div>

    <script>
        document.addEventListener('DOMContentLoaded', function () {
            let boardState = [];

            const loadBoardState = () => {
                const saved = localStorage.getItem('kanbanBoard');
                if (saved) {
                    boardState = JSON.parse(saved);
                }
            };

            const saveBoardState = () => {
                localStorage.setItem('kanbanBoard', JSON.stringify(boardState));
            };

            const createCardElement = (cardData) => {
                const card = document.createElement('div');
                card.className = 'card';
                card.draggable = true;
                card.id = cardData.id;

                const title = document.createElement('span');
                title.textContent = cardData.title;

                const delBtn = document.createElement('button');
                delBtn.className = 'card-del';
                delBtn.textContent = '×';
                delBtn.onclick = function () {
                    card.remove();
                    boardState = boardState.filter(c => c.id !== cardData.id);
                    saveBoardState();
                    updateCounts();
                };

                card.appendChild(title);
                card.appendChild(delBtn);

                card.ondragstart = (e) => {
                    e.dataTransfer.setData('text/plain', card.id);
                };

                return card;
            };

            const updateCounts = () => {
                document.querySelectorAll('[id^=col-]').forEach(col => {
                    const countEl = col.querySelector('.count');
                    const cards = col.querySelector('.card-container').children.length;
                    countEl.textContent = `(${cards})`;
                });
            };

            loadBoardState();

            boardState.forEach(cardData => {
                const column = document.querySelector(cardData.column);
                if (column) {
                    const container = column.querySelector('.card-container');
                    const cardEl = createCardElement(cardData);
                    container.appendChild(cardEl);
                }
            });

            updateCounts();

            document.getElementById('add-card').onclick = function () {
                const input = document.getElementById('new-card');
                const title = input.value.trim();
                if (!title) return;

                const id = 'card-' + Date.now().toString(36) + Math.random().toString(36).substring(2);
                const newCardData = {id, title, column: '#col-todo'};

                boardState.push(newCardData);
                saveBoardState();

                const colTodo = document.querySelector('#col-todo');
                const container = colTodo.querySelector('.card-container');
                const cardEl = createCardElement(newCardData);
                container.appendChild(cardEl);

                input.value = '';
                updateCounts();
            };

            document.querySelectorAll('[id^=col-]').forEach(column => {
                column.addEventListener('dragover', (e) => {
                    e.preventDefault();
                });

                column.addEventListener('drop', (e) => {
                    e.preventDefault();

                    const cardId = e.dataTransfer.getData('text/plain');
                    const card = document.getElementById(cardId);
                    if (!card) return;

                    const prevColumnEl = card.closest('[id^=col-]');
                    const newColumnEl = this;
                    if (prevColumnEl.id === newColumnEl.id) return;

                    const newContainer = newColumnEl.querySelector('.card-container');
                    newContainer.appendChild(card);

                    boardState.forEach(c => {
                        if (c.id === cardId) {
                            c.column = '#' + newColumnEl.id;
                        }
                    });

                    saveBoardState();
                    updateCounts();
                });
            });
        });
    </script>
</body>
</html>
